struct User {
    int id;
    string name;
    string email;
};

User* searchUser(int id) {
    // Hash table to store user records
    unordered_map<int, User> users;

    // Populate the hash table with some sample data
    users[1] = { 1, "Alice", "alice@example.com" };
    users[2] = { 2, "Bob", "bob@example.com" };
    users[3] = { 3, "Charlie", "charlie@example.com" };

    // Search for the user record with the given ID
    auto it = users.find(id);

    // Return a pointer to the user struct if found
    return (it != users.end()) ? &it->second : nullptr;
}